        [@ocaml.doc
          "The ID of the user pool associated with the app client."];
      clientName: ClientNameType.t option
        [@ocaml.doc "The name of the app client."];
      clientId: ClientIdType.t option
        [@ocaml.doc "The ID of the app client."];
